    acc[item.type] = (acc[item.type] ?? 0) + 1;
    return acc;
  }, {});
  return Object.entries(countsByType).reduce((acc, [type, count]) => {
    const base = BASE_PREMIUMS[type];
    const isComponent = base === COMPONENT_BASE_PREMIUM;
    const formsBlock = isComponent && count === BLOCK_SIZE;
    return acc + (formsBlock ? BLOCK_PRICE : base * count);
  }, 0);
};
```

Components (entire module relevant section):
- Constants (literals): `0` (initial reduce), `1` (the `+ 1`), `0` (second reduce initial), plus literals in declarations — counting the function body's literal: `1`, `0`, `0` = 3
- Bindings: `items`, `countsByType`, `acc`, `item`, `acc` (2nd), `type`, `count`, `base`, `isComponent`, `formsBlock` ~ 10
- Invocations: `reduce`, `??`, `Object.entries`, `reduce`, `*`, `+`, plus arithmetic ~ 8
- Conditionals: `?:` (ternary), `&&`, `===` (×2) ~ 4 conditionals worth
- Loops: 2 reduces = 2 × 5 = 10
- Assignments: `acc[item.type] = ...` = 1 × 6 = 6

Approximate Total Mass (function body): 3 + 10 + 16 + 16 + 10 + 6 ≈ **61**

