const PROCESSING_FEE = 5;
const FIRST_INSURANCE_PERCENT = 110;

type Item = { type: string };
type Scenario = { steps: { items: Item[] }[] };

type ItemKind = {
  basePremium: number;
  isComponent: boolean;
};

const ITEM_CATALOG: Record<string, ItemKind> = {
  sword: { basePremium: 100, isComponent: false },
  amulet: { basePremium: 60, isComponent: false },
  staff: { basePremium: 80, isComponent: false },
  potion: { basePremium: 40, isComponent: false },
  rune: { basePremium: 25, isComponent: true },
  moonstone: { basePremium: 25, isComponent: true },
};

const BLOCK_PRICE = 60;
const BLOCK_SIZE = 3;

const countByType = (items: Item[]): Record<string, number> =>
  items.reduce<Record<string, number>>((counts, item) => {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
    return counts;
  }, {});

const premiumForTypeGroup = (type: string, count: number): number => {
  const kind = ITEM_CATALOG[type];
  const formsBlock = kind.isComponent && count === BLOCK_SIZE;
  return formsBlock ? BLOCK_PRICE : kind.basePremium * count;
};

const policyBaseFor = (items: Item[]): number =>
  Object.entries(countByType(items)).reduce(
    (total, [type, count]) => total + premiumForTypeGroup(type, count),
    0,
  );

export const runScenario = (input: unknown): unknown => {
  const items = (input as Scenario).steps[0].items;
  const policyBase = policyBaseFor(items);
  const premium = Math.ceil((policyBase * FIRST_INSURANCE_PERCENT) / 100) + PROCESSING_FEE;
  return { results: [{ premium }] };
};
